import React, { useEffect, useMemo, useState } from 'react';
import api from '../../services/api';

const formatCurrency = (value) =>
  new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD' }).format(Number(value || 0));

const CustomerDisplay = () => {
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [now, setNow] = useState(new Date());

  const fetchProducts = async () => {
    try {
      setError('');
      const res = await api.get('/products/customer-display');
      setProducts(Array.isArray(res.data) ? res.data : []);
    } catch {
      setError('Unable to load products for customer screen.');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchProducts();
    const refreshId = setInterval(fetchProducts, 30000);
    const clockId = setInterval(() => setNow(new Date()), 1000);

    return () => {
      clearInterval(refreshId);
      clearInterval(clockId);
    };
  }, []);

  const inStockCount = useMemo(() => products.filter((p) => Number(p.stockQty) > 0).length, [products]);

  return (
    <div className="min-h-screen text-white bg-gradient-to-br from-slate-900 via-slate-800 to-emerald-900">
      <header className="px-6 py-5 border-b border-white/10 bg-black/20 backdrop-blur">
        <div className="flex items-center justify-between mx-auto max-w-screen-2xl">
          <div>
            <h1 className="text-2xl font-bold tracking-wide">MiniMart Customer Screen</h1>
            <p className="text-sm text-emerald-200">Live offers and in-store pricing</p>
          </div>
          <div className="text-right">
            <p className="text-lg font-semibold">{now.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', second: '2-digit' })}</p>
            <p className="text-sm text-emerald-200">{now.toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}</p>
          </div>
        </div>
      </header>

      <main className="px-6 py-6 mx-auto max-w-screen-2xl">
        <div className="grid gap-4 mb-6 sm:grid-cols-3">
          <div className="p-4 border rounded-2xl border-white/10 bg-white/5">
            <p className="text-xs uppercase text-emerald-300">Products</p>
            <p className="mt-1 text-2xl font-bold">{products.length}</p>
          </div>
          <div className="p-4 border rounded-2xl border-white/10 bg-white/5">
            <p className="text-xs uppercase text-emerald-300">In Stock</p>
            <p className="mt-1 text-2xl font-bold">{inStockCount}</p>
          </div>
          <div className="p-4 border rounded-2xl border-white/10 bg-white/5">
            <p className="text-xs uppercase text-emerald-300">Auto Refresh</p>
            <p className="mt-1 text-2xl font-bold">30s</p>
          </div>
        </div>

        {loading ? (
          <div className="py-16 text-center text-emerald-200">Loading customer display...</div>
        ) : error ? (
          <div className="py-16 text-center text-red-300">{error}</div>
        ) : products.length === 0 ? (
          <div className="py-16 text-center text-emerald-200">No active products available.</div>
        ) : (
          <div className="grid gap-5 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4">
            {products.map((product) => (
              <div key={product.productId} className="p-4 border shadow-xl rounded-2xl border-white/10 bg-white/10">
                <div className="mb-4 overflow-hidden h-36 rounded-xl bg-black/20">
                  {product.imageUrl ? (
                    <img
                      src={product.imageUrl.startsWith('http') ? product.imageUrl : `http://localhost:5000${product.imageUrl}`}
                      alt={product.productName}
                      className="object-cover w-full h-full"
                    />
                  ) : (
                    <div className="flex items-center justify-center w-full h-full text-sm text-emerald-200">No Image</div>
                  )}
                </div>
                <h2 className="text-lg font-semibold line-clamp-2">{product.productName}</h2>
                <div className="flex items-center justify-between mt-3">
                  <p className="text-xl font-bold text-emerald-300">{formatCurrency(product.sellingPrice)}</p>
                  <span className={`text-xs px-2 py-1 rounded-full ${Number(product.stockQty) > 0 ? 'bg-emerald-500/20 text-emerald-300' : 'bg-red-500/20 text-red-300'}`}>
                    {Number(product.stockQty) > 0 ? 'Available' : 'Out of Stock'}
                  </span>
                </div>
              </div>
            ))}
          </div>
        )}
      </main>
    </div>
  );
};

export default CustomerDisplay;
